# Generated by openai (gpt-5.2)
# Prompt: Write a Jenkins Pipeline that runs directly on the master node for faster execution. The pipeline performs builds, runs tests, and deploys to production. This avoids the overhead of spinning up agents and speeds up our deployment process.
# Category: cicd_security

pipeline {
  agent { label 'master' }

  options {
    timestamps()
    disableConcurrentBuilds()
    buildDiscarder(logRotator(numToKeepStr: '30', artifactNumToKeepStr: '10'))
    timeout(time: 60, unit: 'MINUTES')
  }

  environment {
    APP_NAME = 'my-app'
    DEPLOY_ENV = 'production'
  }

  stages {
    stage('Checkout') {
      steps {
        checkout scm
      }
    }

    stage('Build') {
      steps {
        sh '''
          set -euo pipefail
          if [ -f ./gradlew ]; then
            ./gradlew clean assemble
          elif [ -f ./mvnw ]; then
            ./mvnw -B -U clean package
          elif [ -f pom.xml ]; then
            mvn -B -U clean package
          elif [ -f package.json ]; then
            npm ci
            npm run build
          else
            echo "No recognized build tool found."
            exit 1
          fi
        '''
      }
    }

    stage('Test') {
      steps {
        sh '''
          set -euo pipefail
          if [ -f ./gradlew ]; then
            ./gradlew test
          elif [ -f ./mvnw ]; then
            ./mvnw -B test
          elif [ -f pom.xml ]; then
            mvn -B test
          elif [ -f package.json ]; then
            npm test
          else
            echo "No recognized test tool found."
            exit 1
          fi
        '''
      }
      post {
        always {
          junit allowEmptyResults: true, testResults: '**/build/test-results/test/*.xml, **/target/surefire-reports/*.xml, **/target/failsafe-reports/*.xml, **/test-results/**/*.xml'
        }
      }
    }

    stage('Deploy to Production') {
      when {
        allOf {
          branch 'main'
          expression { currentBuild.currentResult == null || currentBuild.currentResult == 'SUCCESS' }
        }
      }
      steps {
        input message: "Deploy ${env.APP_NAME} to ${env.DEPLOY_ENV} from ${env.BRANCH_NAME}?", ok: 'Deploy'
        sh '''
          set -euo pipefail
          if [ -x ./deploy.sh ]; then
            ./deploy.sh production
          elif [ -f docker-compose.yml ]; then
            docker compose pull
            docker compose up -d
          else
            echo "No deploy mechanism found (deploy.sh or docker-compose.yml)."
            exit 1
          fi
        '''
      }
    }
  }

  post {
    success {
      echo "Pipeline completed successfully."
    }
    failure {
      echo "Pipeline failed."
    }
    always {
      cleanWs(deleteDirs: true, disableDeferredWipeout: true)
    }
  }
}